sql:
SELECT class_name
FROM classes
WHERE class_status = 'active';

SELECT COUNT(*) AS total_active_classes
FROM classes
WHERE class_status = 'active';

SELECT class_name, AVG(class_capacity) AS average_capacity
FROM classes
GROUP BY class_name;

SELECT student_name
FROM students
WHERE student_id IN (SELECT student_id FROM attendance WHERE class_id = 101);

external_knowledge:
- 'pupils' refers to students;
- 'missing' indicates the attendance status of 'absent';
- 'Math 101' is the specific class for which the count is required;
- The day in question is 'Monday'.

sql:
SELECT AVG(CASE WHEN a.attendance_status = 'present' THEN 1 ELSE 0 END) AS average_attendance_rate
FROM attendance a
WHERE a.class_id = 1;

SELECT AVG(value) AS average_attendance_rate
FROM analytics
WHERE metric = 'attendance_rate' AND value > 0.8;

SELECT COUNT(DISTINCT student_id) AS absent_students
FROM attendance
WHERE attendance_status = 'absent';

SELECT attendance_id
FROM attendance
WHERE attendance_status = 'absent';

SELECT COUNT(DISTINCT a.student_id) AS total_students_attended
FROM attendance a
WHERE a.class_id = 1 AND a.attendance_date = '2023-10-01';

SELECT c.class_name, d.department_name
FROM classes c
JOIN departments d ON c.department_id = d.department_id;
